#include <stdio.h>
#include <math.h>

long long phi(long long n) {
    long long result = n;
    for (long long p = 2; p * p <= n; ++p) {
        if (n % p == 0) {
            while (n % p == 0) n /= p;
            result -= result / p;
        }
    }
    if (n > 1) result -= result / n;
    return result;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        printf("%lld\n", phi(N));
    }
    return 0;
}

